import React, {useState} from "react";
import {useNavigate} from "react-router-dom";
import Home from "./Home";
import StudentDetails from "./StudentDetails";
import StudentForm from "./StudentForm";
import Search from "./Search";
import Profile from "./Profile";
import "../styles/Dashboard.css";

export default function Dashboard(){
const [activeTab, setActiveTab] = useState("home");
const navigate = useNavigate();

const handleLogout = () => {
localStorage.removeItem("user");
navigate("/");
};

const renderContent = () => {
switch(activeTab){
case "home":
return <Home/>;
case "details":
return <StudentDetails/>;
case "add":
return <StudentForm/>;
case "search":
return <Search/>;
case "profile":
return <Profile/>;
default:
return <Home/>;
}
};

return(
<div className="dashboard-container">
{/* Sidebar */}
<nav className="sidebar">
<div className="sidebar-header">
<h3 className="sidebar-title">
<i className="bi bi-graph-up"></i> KAS
</h3>
<p className="sidebar-subtitle">Knowledge Analytics</p>
</div>

<div className="sidebar-menu">
<button 
className={`sidebar-link ${activeTab === "home" ? "active" : ""}`}
onClick={() => setActiveTab("home")}
>
<i className="bi bi-house-fill"></i> Home
</button>

<button 
className={`sidebar-link ${activeTab === "profile" ? "active" : ""}`}
onClick={() => setActiveTab("profile")}
>
<i className="bi bi-person-fill"></i> Profile
</button>

<button 
className={`sidebar-link ${activeTab === "add" ? "active" : ""}`}
onClick={() => setActiveTab("add")}
>
<i className="bi bi-plus-circle-fill"></i> Add Student
</button>

<button 
className={`sidebar-link ${activeTab === "details" ? "active" : ""}`}
onClick={() => setActiveTab("details")}
>
<i className="bi bi-table"></i> Student Details
</button>

<button 
className={`sidebar-link ${activeTab === "search" ? "active" : ""}`}
onClick={() => setActiveTab("search")}
>
<i className="bi bi-search"></i> Search Student
</button>

<hr className="sidebar-divider"/>

<button 
className="sidebar-link logout-btn"
onClick={handleLogout}
>
<i className="bi bi-box-arrow-right"></i> Logout
</button>
</div>
</nav>

{/* Main Content */}
<div className="dashboard-content">
<div className="content-area">
{renderContent()}
</div>
</div>
</div>
);
}
